object AppConfig {
    val version = "1.0"
    val debug = false
}
println(AppConfig.version)

class User(val name: String) {
    companion object {
        fun create(name: String) = User(name)
    }
}
val u = User.create("Alice")
println(u.name)

class Circle {
    companion object {
        const val PI = 3.14159
    }
}
println(Circle.PI)

class Stamp(val label: String) {
    companion object {
        var total = 0
    }
    init { total++ }
}
Stamp("A")
Stamp("B")
println(Stamp.total)

class Token(val value: String) {
    companion object Generator {
        fun random() = Token("tok_${(1000..9999).random()}")
    }
}
println(Token.random().value.startsWith("tok_"))

interface Greeter {
    fun greet(): String
}
val g = object : Greeter {
    override fun greet() = "Hello!"
}
println(g.greet())

open class Logger {
    open fun log(msg: String) = println("LOG: $msg")
}
val silent = object : Logger() {
    override fun log(msg: String) { /* do nothing */ }
}
silent.log("test")
println("done")

